const AWS = require('aws-sdk');
const dynamodb = new AWS.DynamoDB.DocumentClient({ region: 'your-region' });
const sqs = new AWS.SQS({ region: 'your-region' });
const sns = new AWS.SNS({ region: 'your-region' });

exports.handler = async (event) => {
  const orders = JSON.parse(event.Records[0].body);

  for (let order of orders) {
    try {
      // Process the order by calling external payment APIs
      const paymentResponse = await callPaymentAPI(order);
      
      // Update DynamoDB with payment response
      await updateDynamoDB(order, paymentResponse);

      console.log(`Order processed successfully: ${order.id}`);
    } catch (err) {
      console.error(err);
    }
  }

  return {
    statusCode: 200,
    status: 'success',
    body: JSON.stringify('Orders processed successfully'),
  };
};

const callPaymentAPI = async (order) => {
  try {
    const paymentResponse = await axios.post(`https://api.example.com/payments`, order);
    return paymentResponse.data;
  } catch (err) {
    console.error(err);
  }
};

const updateDynamoDB = async (order, paymentResponse) => {
  try {
    await dynamodb.update({
      TableName: 'orders',
      Key: { id: order.id },
      UpdateExpression: 'set #status = :s, #payment_response = :pr',
      ExpressionAttributeNames: {
        '#status': 'status',
        '#payment_response': 'payment_response'
      },
      ExpressionAttributeValues: {
        ':s': paymentResponse.status,
        ':pr': paymentResponse
      }
    }).promise();
  } catch (err) {
    console.error(err);
  }
};